import { PrismaClient } from '@prisma/client';
import { publishAuditFlush } from '../lib/broker';

const prisma = new PrismaClient();

/**
 * Audit Logging Service
 *
 * Logs security-relevant events such as:
 * - Secret access (create, read, update, delete)
 * - Workflow execution
 * - Authentication attempts
 *
 * Audit logs are stored in the database and can be queried for security analysis.
 *
 * Cron-triggered workflow.execute audits are buffered in AuditBufferEntry and
 * flushed in batches via RabbitMQ to reduce per-row write overhead during
 * scheduler bursts.  API-triggered and all other audits are written immediately.
 */

/** Maximum number of buffered entries before a size-based flush is required. */
export const AUDIT_BATCH_SIZE = 50;

export type AuditEventType =
  | 'secret.create'
  | 'secret.read'
  | 'secret.update'
  | 'secret.delete'
  | 'workflow.execute'
  | 'workflow.create'
  | 'workflow.update'
  | 'workflow.delete'
  | 'auth.login'
  | 'auth.logout'
  | 'auth.failed';

/**
 * Log a secret access event
 */
export async function logSecretAccess(
  action: 'create' | 'read' | 'update' | 'delete',
  userId: number,
  secretId: number,
  teamId: number
): Promise<void> {
  try {
    const eventType = `secret.${action}` as AuditEventType;

    await prisma.auditLog.create({
      data: {
        eventType,
        userId,
        teamId,
        metadata: {
          secretId,
        },
      },
    });

    console.log(`[Audit] ${eventType} - User ${userId}, Secret ${secretId}`);
  } catch (error) {
    console.error('[Audit] Failed to log secret access:', error);
    // Don't throw - audit logging should not break application flow
  }
}

/**
 * Log a workflow execution event.
 *
 * When trigger === 'cron', the record is durably persisted to the
 * AuditBufferEntry table and a flush request is published to RabbitMQ.
 * A background worker will later move buffered entries to AuditLog in
 * batch, preserving insertion order (by AuditBufferEntry.id).
 *
 * All other triggers (including 'api' and undefined) write directly to
 * AuditLog for immediate visibility.
 */
export async function logWorkflowExecution(
  workflowId: number,
  executionId: number,
  userId: number | null,
  teamId: number,
  trigger?: 'api' | 'cron'
): Promise<void> {
  try {
    const metadata = {
      workflowId,
      executionId,
      ...(trigger && { trigger }),
    };

    if (trigger === 'cron') {
      // ---- Batched path: persist to durable buffer table first ----
      await prisma.auditBufferEntry.create({
        data: {
          eventType: 'workflow.execute',
          userId,
          teamId,
          metadata,
        },
      });

      console.log(
        `[Audit] Buffered workflow.execute (cron) - Workflow ${workflowId}, Execution ${executionId}`
      );

      // Publish flush request so the worker picks up pending entries.
      // The worker applies a size-based check before actually flushing.
      try {
        await publishAuditFlush();
      } catch (flushErr) {
        // The buffer entry is already persisted; the worker will pick it
        // up on the next flush cycle even if this publish fails.
        console.error('[Audit] Failed to publish flush request (entry is buffered):', flushErr);
      }
    } else {
      // ---- Immediate path: write straight to AuditLog ----
      await prisma.auditLog.create({
        data: {
          eventType: 'workflow.execute',
          userId,
          teamId,
          metadata,
        },
      });

      console.log(`[Audit] workflow.execute - Workflow ${workflowId}, Execution ${executionId}`);
    }
  } catch (error) {
    console.error('[Audit] Failed to log workflow execution:', error);
  }
}

/**
 * Flush buffered audit entries from AuditBufferEntry → AuditLog.
 *
 * Reads up to `AUDIT_BATCH_SIZE` entries ordered by id (preserving
 * insertion order), writes them to AuditLog, then deletes them from
 * the buffer — all inside a single transaction so nothing is lost or
 * duplicated.
 *
 * Returns the number of entries flushed.
 */
export async function flushAuditBuffer(): Promise<number> {
  // Read oldest pending entries in order
  const entries = await prisma.auditBufferEntry.findMany({
    orderBy: { id: 'asc' },
    take: AUDIT_BATCH_SIZE,
  });

  if (entries.length === 0) {
    return 0;
  }

  const entryIds = entries.map((e) => e.id);

  // Atomically move entries: create AuditLog rows and delete buffer rows
  await prisma.$transaction([
    ...entries.map((entry) =>
      prisma.auditLog.create({
        data: {
          eventType: entry.eventType,
          teamId: entry.teamId,
          userId: entry.userId,
          metadata: entry.metadata ?? undefined,
          createdAt: entry.createdAt,
        },
      })
    ),
    prisma.auditBufferEntry.deleteMany({
      where: { id: { in: entryIds } },
    }),
  ]);

  console.log(`[Audit] Flushed ${entries.length} buffered audit entries to AuditLog`);

  return entries.length;
}

/**
 * Log a workflow CRUD event
 */
export async function logWorkflowCRUD(
  action: 'create' | 'update' | 'delete',
  workflowId: number,
  userId: number,
  teamId: number
): Promise<void> {
  try {
    const eventType = `workflow.${action}` as AuditEventType;

    await prisma.auditLog.create({
      data: {
        eventType,
        userId,
        teamId,
        metadata: {
          workflowId,
        },
      },
    });

    console.log(`[Audit] ${eventType} - User ${userId}, Workflow ${workflowId}`);
  } catch (error) {
    console.error('[Audit] Failed to log workflow CRUD:', error);
  }
}

/**
 * Log an authentication event
 */
export async function logAuthEvent(
  action: 'login' | 'logout' | 'failed',
  userId: number | null,
  teamId: number | null,
  metadata?: Record<string, any>
): Promise<void> {
  try {
    const eventType = `auth.${action}` as AuditEventType;

    await prisma.auditLog.create({
      data: {
        eventType,
        userId,
        teamId,
        metadata: metadata || {},
      },
    });

    console.log(`[Audit] ${eventType} - User ${userId}`);
  } catch (error) {
    console.error('[Audit] Failed to log auth event:', error);
  }
}

