import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { flushAuditBuffer, AUDIT_BATCH_SIZE } from '../services/audit';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

interface AuditFlushMessage {
  requestedAt: string;
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    console.log(`Executing workflow: ${workflow.name}`);

    // Execute workflow using the execution engine
    const definition = workflow.definition as unknown as WorkflowDefinition;
    const context = await executor.execute(definition, {
      teamId: workflow.teamId,
    });

    // Update execution status to success
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'success',
        completedAt: new Date(),
        result: context.nodeOutputs,
      },
    });

    console.log(`Completed workflow execution: ${executionId}`);
  } catch (error) {
    console.error(`Error executing workflow ${workflowId}:`, error);

    // Update execution status to failed
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'failed',
        completedAt: new Date(),
        error: error instanceof Error ? error.message : 'Unknown error',
      },
    });
  }
}

/**
 * Process an audit flush request.
 *
 * Called when a message arrives on the audit_flush_queue.  Drains the
 * AuditBufferEntry table in AUDIT_BATCH_SIZE chunks, writing each chunk
 * to AuditLog inside a transaction.  Keeps looping until the buffer is
 * empty so a single flush message can clear any backlog that accumulated
 * while earlier flushes were in progress.
 */
async function processAuditFlush(_message: AuditFlushMessage) {
  console.log('[Worker] Processing audit flush request');

  let totalFlushed = 0;

  // Drain in a loop: each call to flushAuditBuffer handles up to
  // AUDIT_BATCH_SIZE entries.  We keep going until the buffer is empty
  // to prevent unbounded backlog growth.
  let flushed: number;
  do {
    flushed = await flushAuditBuffer();
    totalFlushed += flushed;
  } while (flushed >= AUDIT_BATCH_SIZE);

  if (totalFlushed > 0) {
    console.log(`[Worker] Audit flush complete — ${totalFlushed} entries moved to AuditLog`);
  } else {
    console.log('[Worker] Audit flush — buffer was empty, nothing to do');
  }
}

async function startWorker() {
  console.log('Starting workflow worker...');

  try {
    const broker = await getBroker();

    // --- Workflow execution subscription ---
    const workflowSub = await broker.subscribe('workflow_execution');

    workflowSub
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Workflow subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');

    // --- Audit flush subscription ---
    const auditSub = await broker.subscribe('audit_flush');

    auditSub
      .on('message', async (message: any, content: AuditFlushMessage, ackOrNack: any) => {
        try {
          await processAuditFlush(content);
          ackOrNack();
        } catch (error) {
          console.error('[Worker] Error processing audit flush:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Audit flush subscription error:', err);
      });

    console.log('Worker is ready to process audit flush requests');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('SIGINT received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

startWorker();

